import './SpendingAnalytics.css';


function SpendingAnalytics() {
    const monthlyExpenses = [
            { month: "Jan", expense: 100 },
            { month: "Feb", expense: 100 },
            { month: "Mar", expense: 0 },
            { month: "Apr", expense: 0 },
            { month: "May", expense: 0 },
            { month: "Jun", expense: 0 },
            { month: "Jul", expense: 0 },
            { month: "Aug", expense: 0 },
            { month: "Sep", expense: 0 },
            { month: "Oct", expense: 0 },
            { month: "Nov", expense: 0 },
            { month: "Dec", expense: 0 }
        ];
    return (
    <>
    <MonthlyExpenseChart/>
    </>
  );
}
export default SpendingAnalytics;
